#include <stdio.h>
#define MOD 1000000007

long long powmod(long long a, long long b) {
    long long res = 1;
    while (b) {
        if (b & 1) res = (res * a) % MOD;
        a = (a * a) % MOD;
        b >>= 1;
    }
    return res;
}

long long calculate_f(int M, int N, int X, int D, long long* coefficients) {
    long long result = 0;
    for (int i = 0; i <= M; i++) {
        long long temp = 1;
        for (int j = 0; j < i; j++) {
            temp = (temp * coefficients[0]) % MOD;
        }
        for (int j = 0; j < M - i; j++) {
            temp = (temp * coefficients[D]) % MOD;
        }
        result = (result + temp) % MOD;
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int M, N, X;
        scanf("%d %d %d", &M, &N, &X);
        int D;
        scanf("%d", &D);
        long long coefficients[D + 1];
        for (int i = 0; i <= D; i++) {
            scanf("%lld", &coefficients[i]);
        }
        long long result = calculate_f(M, N, X, D, coefficients);
        printf("%lld\n", result);
    }
    return 0;
}

