import java.util.Scanner;
public class Main {
    static final long MOD = 1000000007;
    public static long powmod(long a, long b) {
        long res = 1;
        while (b > 0) {
            if ((b & 1) == 1) res = (res * a) % MOD;
            a = (a * a) % MOD;
            b >>= 1;
        }
        return res;
    }

    public static long calculate_f(int M, int N, int X, int D, long[] coefficients) {
        long result = 0;
        for (int i = 0; i <= M; i++) {
            long temp = 1;
            for (int j = 0; j < i; j++) {
                temp = (temp * coefficients[0]) % MOD;
            }
            for (int j = 0; j < M - i; j++) {
                temp = (temp * coefficients[D]) % MOD;
            }
            result = (result + temp) % MOD;
        }
        return result;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int M = scanner.nextInt();
            int N = scanner.nextInt();
            int X = scanner.nextInt();
            int D = scanner.nextInt();
            long[] coefficients = new long[D + 1];
            for (int i = 0; i <= D; i++) {
                coefficients[i] = scanner.nextLong();
            }
            long result = calculate_f(M, N, X, D, coefficients);
            System.out.println(result);
        }
    }
}

